code = """import json
import os

# Load NASDAQ Capital Market stocks
var_key = 'var_functions.query_db:0'
file_path = locals().get(var_key)

with open(file_path, 'r') as f:
    nasdaq_capital_stocks = json.load(f)

ticker_to_company = {stock['Symbol']: stock['Company Description'] for stock in nasdaq_capital_stocks}
all_tickers = list(ticker_to_company.keys())

# Function to calculate volatile days
def count_volatile_days(data):
    volatile_count = 0
    for day in data:
        high = float(day['High'])
        low = float(day['Low'])
        intraday_range = high - low
        twenty_pct_low = 0.20 * low
        if intraday_range > twenty_pct_low:
            volatile_count += 1
    return volatile_count

# Current data we have
existing_results = {}

# AGMH - var_functions.query_db:26
key = 'var_functions.query_db:26'
if key in locals():
    fp = locals()[key]
    if isinstance(fp, str) and os.path.exists(fp):
        with open(fp, 'r') as f:
            existing_results['AGMH'] = count_volatile_days(json.load(f))

# Process BHAT
key = 'var_functions.query_db:42'
if key in locals():
    fp = locals()[key]
    if isinstance(fp, str) and os.path.exists(fp):
        with open(fp, 'r') as f:
            existing_results['BHAT'] = count_volatile_days(json.load(f))

# Process BCLI
key = 'var_functions.query_db:38'
if key in locals():
    fp = locals()[key]
    if isinstance(fp, str) and os.path.exists(fp):
        with open(fp, 'r') as f:
            existing_results['BCLI'] = count_volatile_days(json.load(f))

# Process ALACU
key = 'var_functions.query_db:30'
if key in locals():
    fp = locals()[key]
    if isinstance(fp, str) and os.path.exists(fp):
        with open(fp, 'r') as f:
            existing_results['ALACU'] = count_volatile_days(json.load(f))

print(f"Currently processed: {existing_results}")
print(f"Total tickers to process: {len(all_tickers)}")

# Show companies sorted by volatile days so far
sorted_results = sorted(existing_results.items(), key=lambda x: x[1], reverse=True)

result = {
    "current_results": [{"ticker": t, "volatile_days": v, "company": ticker_to_company[t]} for t, v in sorted_results],
    "total_processed": len(existing_results),
    "remaining": len(all_tickers) - len(existing_results)
}

print(f"__RESULT__:")
print(json.dumps(result))"""

